import { query } from "@anthropic-ai/claude-agent-sdk";

for await (const message of query({
  prompt: "Hello Claude",
  options: { maxTurns: 1 }
})) {
  if (message.type === "system" && message.subtype === "init") {
    console.log("Available slash commands:", message.slash_commands);
    // ["compact", "clear", "context", "usage", ...]
  }
}

import { query } from "@anthropic-ai/claude-agent-sdk";

// Trigger compaction from code
for await (const message of query({
  prompt: "/compact",
  options: { maxTurns: 1 }
})) {
  if (message.type === "system" && message.subtype === "compact_boundary") {
    console.log("Compaction completed");
    console.log("Pre-compaction tokens:", message.compact_metadata.pre_tokens);
    console.log("Trigger:", message.compact_metadata.trigger); // "manual" | "auto"
  }
}
// Clear and start a fresh session
for await (const message of query({
  prompt: "/clear",
  options: { maxTurns: 1 }
})) {
  if (message.type === "system" && message.subtype === "init") {
    console.log("New session started:", message.session_id);
  }
}

// Defensive SDK usage
const initData = await getInitMessage(session);
const canClear = initData.slash_commands.includes("clear");
const canCompact = initData.slash_commands.includes("compact");

if (tokenUsage > 0.8 && canCompact) {
  await sendCommand("/compact Retain the database migration work");
} else if (tokenUsage > 0.95 && canClear) {
  await sendCommand("/clear");
}
